using UnityEngine;

public class LifecycleExample : MonoBehaviour
{
    // Called when the script is first initialized
    void Awake()
    {
        Debug.Log("1. Awake — Called when GameObject is created");
    }

    // Called when the GameObject is active and enabled
    void OnEnable()
    {
        Debug.Log("2. OnEnable — Called when GameObject is enabled");
    }

    // Called before the first frame
    void Start()
    {
        Debug.Log("3. Start — Called before the first frame");
    }

    // Called every frame (~60 times per second)
    void Update()
    {
        Debug.Log("4. Update — Called every frame");
    }

    // Called at fixed time intervals (for physics)
    void FixedUpdate()
    {
        Debug.Log("5. FixedUpdate — Called on fixed time intervals");
    }

    // Called after all Update calls
    void LateUpdate()
    {
        Debug.Log("6. LateUpdate — Called after Update");
    }

    // Called when the GameObject is disabled
    void OnDisable()
    {
        Debug.Log("7. OnDisable — Called when GameObject is disabled");
    }

    // Called when the GameObject is destroyed
    void OnDestroy()
    {
        Debug.Log("8. OnDestroy — Called when GameObject is destroyed");
    }
}

phase2.brokenCode:
using UnityEngine;

public class LifecycleError : MonoBehaviour
{
    public GameObject target;

    void Awake()
    {
        // Error: trying to use target before it's assigned
        Debug.Log(target.name);  // target is null!
    }

    void Start()
    {
        // Safe: target should be assigned by now
        Debug.Log(target.name);  // Works if assigned in Inspector
    }
}

phase2.explanation:
`Awake()` runs as soon as the GameObject is created. If a field isn't assigned in the Inspector yet, it might be `null`.

**The fix:**
- Assign the target in the Inspector
- Or check for `null` before using it

```csharp
void Awake()
{
    if (target != null)
    {
        Debug.Log(target.name);
    }
}
```

**Sharp-chan says:**
"`Awake()` is for your own initialization. Don't rely on other objects being ready yet. Use `Start()` for that."
